import{_ as o,o as t,c as i,ak as n}from"./chunks/framework.Dx0ZwfXr.js";const g=JSON.parse('{"title":"Migrate from v1","description":"","frontmatter":{},"headers":[],"relativePath":"articles/migrating-from-v1.md","filePath":"articles/migrating-from-v1.md"}'),d={name:"articles/migrating-from-v1.md"};function a(r,e,s,c,l,p){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="migrate-from-v1" tabindex="-1">Migrate from v1 <a class="header-anchor" href="#migrate-from-v1" aria-label="Permalink to “Migrate from v1”">​</a></h1><p>Version <code>2.0.0-beta.1</code> keeps <code>RdpControl</code> as the main entry point, but the configuration model now distinguishes between embedded and external sessions.</p><p>Breaking changes and additions:</p><ul><li><code>RdpClientConfiguration.SessionMode</code> selects embedded vs external hosting.</li><li><code>RdpClientConfiguration.External</code> contains launcher, credential, temp-file, and cleanup settings.</li><li><code>RdpClientConfiguration.RemoteApp</code> is the new dedicated model for RemoteApp publishing. Do not overload <code>Program</code> for that purpose.</li><li><code>ConnectedEventArgs</code> and <code>DisconnectedEventArgs</code> now expose <code>SessionMode</code>.</li><li>External mode does not expose an <code>IRdpClient</code> instance because the session is hosted by a separate process.</li><li>Security configuration now includes both high-level modes (<code>RemoteCredentialGuard</code>, <code>RestrictedAdminMode</code>) and low-level flags (<code>DisableCredentialsDelegation</code>, <code>RedirectedAuthentication</code>, <code>RestrictedLogon</code>).</li><li>Invalid mixed-mode combinations are now rejected during validation instead of being silently ignored.</li></ul><p>See <a href="./support-matrix">Support Matrix</a> for the supported feature split between embedded and external sessions.</p>',5)])])}const f=o(d,[["render",a]]);export{g as __pageData,f as default};
